// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 300000

// Function to calculate the d-th Fibonacci number
long long fibonacci(int d) {
    if (d <= 1) return d;
    long long a = 0, b = 1;
    for (int i = 2; i <= d; i++) {
        long long temp = (a + b) % MOD;
        a = b;
        b = temp;
    }
    return b;
}

// Function to perform BFS traversal
void bfs(int v, int k, int a, int b, int *values, int **graph, int *distances) {
    for (int i = 0; i < MAXN; i++) distances[i] = -1;
    distances[v] = 0;
    values[v] = (values[v] + fibonacci(distances[v])) % MOD;
    int *queue = (int *)malloc(MAXN * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = v;
    while (front < rear) {
        int u = queue[front++];
        for (int i = 0; i < graph[u][0]; i++) {
            int w = graph[u][i + 1];
            if (distances[w] == -1) {
                distances[w] = distances[u] + 1;
                if (distances[w] <= k) {
                    values[w] = (values[w] + fibonacci(distances[w])) % MOD;
                }
                queue[rear++] = w;
            }
        }
    }
    free(queue);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc((N + 1) * sizeof(int));
            graph[i][0] = 0;
        }
        for (int i = 0; i < N - 1; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            x--;
            y--;
            graph[x][++graph[x][0]] = y;
            graph[y][++graph[y][0]] = x;
        }
        int *values = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) values[i] = 0;
        int *distances = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < Q; i++) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int v, k, a, b;
                scanf("%d %d %d %d", &v, &k, &a, &b);
                v--;
                bfs(v, k, a, b, values, graph, distances);
            } else {
                int v;
                scanf("%d", &v);
                v--;
                printf("%d\n", values[v]);
            }
        }
        for (int i = 0; i < N; i++) free(graph[i]);
        free(graph);
        free(values);
        free(distances);
    }
    return 0;
}

