}

// Function to perform BFS traversal
void bfs(int v, int k, int a, int b, vector<long long> &values, vector<vector<int>> &graph, vector<int> &distances) {
    for (int i = 0; i < MAXN; i++) distances[i] = -1;
    distances[v] = 0;
    values[v] = (values[v] + fibonacci(distances[v])) % MOD;
    queue<int> q;
    q.push(v);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int w : graph[u]) {
            if (distances[w] == -1) {
