import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 300000;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[][] graph = new int[N][N + 1];
            for (int i = 0; i < N; i++) graph[i][0] = 0;
            for (int i = 0; i < N - 1; i++) {
                int x = sc.nextInt() - 1;
                int y = sc.nextInt() - 1;
                graph[x][++graph[x][0]] = y;
                graph[y][++graph[y][0]] = x;
            }
            long[] values = new long[N];
            int[] distances = new int[N];
            for (int i = 0; i < Q; i++) {
                int type = sc.nextInt();
                if (type == 1) {
                    int v = sc.nextInt() - 1;
                    int k = sc.nextInt();
                    int a = sc.nextInt();
                    int b = sc.nextInt();
                    bfs(v, k, a, b, values, graph, distances);
                } else {
                    int v = sc.nextInt() - 1;
                    System.out.println(values[v]);
                }
            }
        }
    }
    public static long fibonacci(int d) {
        if (d <= 1) return d;
        long a = 0, b = 1;
        for (int i = 2; i <= d; i++) {
            long temp = (a + b) % MOD;
            a = b;
            b = temp;
        }
        return b;
    }
    public static void bfs(int v, int k, int a, int b, long[] values, int[][] graph, int[] distances) {
        for (int i = 0; i < MAXN; i++) distances[i] = -1;
        distances[v] = 0;
        values[v] = (values[v] + fibonacci(distances[v])) % MOD;
        Queue<Integer> q = new LinkedList<>();
        q.add(v);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int i = 1; i <= graph[u][0]; i++) {
                int w = graph[u][i];
                if (distances[w] == -1) {
                    distances[w] = distances[u] + 1;
                    if (distances[w] <= k) {
                        values[w] = (values[w] + fibonacci(distances[w])) % MOD;
                    }
                    q.add(w);
                }
            }
        }
    }
}

